customCSS:
/* Power & Efficiency Theme Overrides */

/* Make power stat prominent */
.stat-card.power {
  grid-column: span 2;
  background: linear-gradient(135deg, rgba(250, 204, 21, 0.15) 0%, rgba(26, 31, 46, 1) 100%);
  border: 2px solid rgba(250, 204, 21, 0.4);
}

.stat-card.power .stat-value {
  font-size: 2.5rem;
  color: var(--neon-yellow);
}

/* Efficiency sub-stat highlight */
.stat-card.power .stat-sub {
  font-size: 1rem;
  color: var(--neon-green);
  font-weight: 600;
}

/* Temperature gauge emphasis */
.temp-gauge {
  margin-top: 0.5rem;
}

.temp-bar {
  height: 8px;
}

/* Miner power display */
.miner-stat.power {
  background: rgba(250, 204, 21, 0.1);
  border: 1px solid rgba(250, 204, 21, 0.2);
}

.miner-stat.power .miner-stat-value {
  font-size: 1.3rem;
}

/* Efficiency coloring for miners */
.miner-card[data-efficiency='good'] {
  border-left: 4px solid var(--neon-green);
}

.miner-card[data-efficiency='average'] {
  border-left: 4px solid var(--neon-yellow);
}

.miner-card[data-efficiency='poor'] {
  border-left: 4px solid var(--neon-red);
}

/* Charts row - give power chart priority */
.charts-row {
  grid-template-columns: 1fr 1fr;
}

/* Earnings calculator shows cost/profit prominently */
.earnings-card {
  border: 2px solid rgba(74, 222, 128, 0.3);
}

/* Footer power cost display */
.footer-power-cost {
  display: flex;
  gap: 2rem;
  justify-content: center;
  padding: 1rem 0;
  border-top: 1px solid rgba(250, 204, 21, 0.2);
  margin-top: 1rem;
}

.footer-power-cost .cost-item {
  text-align: center;
}

.footer-power-cost .cost-value {
  font-family: var(--font-mono);
  font-size: 1.2rem;
  color: var(--neon-yellow);
}

.footer-power-cost .cost-label {
  font-size: 0.8rem;
  color: var(--text-muted);
}
